with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)
def build_map(data):
    m = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                m[(name, fw['framework'], pkg['id'])] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return m
b = build_map(baseline)
a = build_map(after)
all_keys = sorted(set(b.keys()) | set(a.keys()))
changes, unchanged = [], []
for k in all_keys:
    proj, fw, pkg = k
    bv, av = b.get(k), a.get(k)
    if bv and av:
        if bv[1] != av[1]:
            changes.append((proj, fw, pkg, bv[1], av[1], 'Aligned to highest version'))
        else:
            unchanged.append((proj, fw, pkg, av[1]))
    elif bv and not av:
        changes.append((proj, fw, pkg, bv[1], '-', 'Removed'))
    elif av and not bv:
        changes.append((proj, fw, pkg, '-', av[1], 'Added'))
print('=== CHANGES ===')
for c in changes: print(f'  {c[0]} ({c[1]}) | {c[2]} | {c[3]} -> {c[4]} | {c[5]}')
if not changes: print('  None')
print()
print('=== UNCHANGED ===')
for u in unchanged: print(f'  {u[0]} ({u[1]}) | {u[2]} | {u[3]}')
"
